output:
Given your stack (AWS EKS + Terraform), the simplest option is **S3 + CloudFront**:

1. **S3 bucket** with static website hosting enabled
2. **CloudFront distribution** in front for HTTPS + caching
3. **Route 53** for DNS (assuming you're already using it)

Terraform it so it's consistent with everything else:

```hcl
resource "aws_s3_bucket" "marketing" {
  bucket = "helios-marketing-site"
}

resource "aws_s3_bucket_website_configuration" "marketing" {
  bucket = aws_s3_bucket.marketing.id
  index_document { suffix = "index.html" }
  error_document { key = "404.html" }
}

resource "aws_cloudfront_distribution" "marketing" {
  origin {
    domain_name              = aws_s3_bucket.marketing.bucket_regional_domain_name
    origin_id                = "s3-marketing"
    origin_access_control_id = aws_cloudfront_origin_access_control.marketing.id
  }

  enabled             = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods        = ["GET", "HEAD"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = "s3-marketing"
    viewer_protocol_policy = "redirect-to-https"
    forwarded_values {
      query_string = false
      cookies { forward = "none" }
    }
  }

  viewer_certificate {
    acm_certificate_arn = var.cert_arn
    ssl_support_method  = "sni-only"
  }

  restrictions {
    geo_restriction { restriction_type = "none" }
  }
}
```

Deploy via GitHub Actions — just `aws s3 sync` the build output to the bucket, then invalidate the CloudFront cache.

**Don't** put it in EKS. No reason to run a container for static files. S3 + CloudFront is cheaper, faster, and zero maintenance.
